package main

import (
	"bytes"
	"encoding/binary"
	"errors"
	"fmt"
	"io"
	"os"
	"path/filepath"
)

// Minimal 64-bit little-endian ELF layout code (no debug/elf).

const (
	EI_NIDENT = 16

	ELFCLASS64 = 2
	ELFDATA2LSB = 1

	SHT_NULL     = 0
	SHT_SYMTAB   = 2
	SHT_STRTAB   = 3
	SHT_RELA     = 4
	SHT_DYNSYM   = 11

	SHN_UNDEF = 0
)

type elf64Ehdr struct {
	Ident     [EI_NIDENT]byte
	Type      uint16
	Machine   uint16
	Version   uint32
	Entry     uint64
	Phoff     uint64
	Shoff     uint64
	Flags     uint32
	Ehsize    uint16
	Phentsize uint16
	Phnum     uint16
	Shentsize uint16
	Shnum     uint16
	Shstrndx  uint16
}

type elf64Shdr struct {
	Name      uint32
	Type      uint32
	Flags     uint64
	Addr      uint64
	Off       uint64
	Size      uint64
	Link      uint32
	Info      uint32
	Addralign uint64
	Entsize   uint64
}

type elf64Sym struct {
	Name  uint32
	Info  byte
	Other byte
	Shndx uint16
	Value uint64
	Size  uint64
}

type elf64Rela struct {
	Off    uint64
	Info   uint64
	Addend int64
}

func relaSym(info uint64) uint32  { return uint32(info >> 32) }
func relaType(info uint64) uint32 { return uint32(info & 0xffffffff) }
func makeRelaInfo(sym uint32, typ uint32) uint64 {
	return (uint64(sym) << 32) | uint64(typ)
}

func readAtFull(f *os.File, off int64, size int) ([]byte, error) {
	b := make([]byte, size)
	if _, err := f.ReadAt(b, off); err != nil {
		return nil, err
	}
	return b, nil
}

func readStructAt[T any](f *os.File, off int64, out *T) error {
	var sz int
	sz = binary.Size(*out)
	b, err := readAtFull(f, off, sz)
	if err != nil {
		return err
	}
	return binary.Read(bytes.NewReader(b), binary.LittleEndian, out)
}

func readCString(tab []byte, off uint32) string {
	if int(off) >= len(tab) {
		return ""
	}
	p := tab[off:]
	if i := bytes.IndexByte(p, 0); i >= 0 {
		return string(p[:i])
	}
	return string(p)
}

type section struct {
	hdr  elf64Shdr
	name string
	idx  int
}

type dynsym struct {
	idx  int
	sym  elf64Sym
	name string
}

func loadSections(f *os.File, eh elf64Ehdr) ([]section, []byte, error) {
	if eh.Shentsize == 0 || eh.Shnum == 0 {
		return nil, nil, errors.New("no section headers")
	}
	if eh.Shentsize != uint16(binary.Size(elf64Shdr{})) {
		return nil, nil, fmt.Errorf("unexpected section header size: %d", eh.Shentsize)
	}
	shdrs := make([]elf64Shdr, int(eh.Shnum))
	for i := 0; i < int(eh.Shnum); i++ {
		if err := readStructAt(f, int64(eh.Shoff)+int64(i)*int64(eh.Shentsize), &shdrs[i]); err != nil {
			return nil, nil, fmt.Errorf("read shdr[%d]: %w", i, err)
		}
	}
	if int(eh.Shstrndx) >= len(shdrs) {
		return nil, nil, fmt.Errorf("invalid e_shstrndx %d", eh.Shstrndx)
	}
	shstr := shdrs[eh.Shstrndx]
	if shstr.Type != SHT_STRTAB {
		return nil, nil, fmt.Errorf("section header string table is not STRTAB (type=%d)", shstr.Type)
	}
	shstrtab, err := readAtFull(f, int64(shstr.Off), int(shstr.Size))
	if err != nil {
		return nil, nil, fmt.Errorf("read .shstrtab: %w", err)
	}
	secs := make([]section, len(shdrs))
	for i := range shdrs {
		secs[i] = section{hdr: shdrs[i], name: readCString(shstrtab, shdrs[i].Name), idx: i}
	}
	return secs, shstrtab, nil
}

func findSection(secs []section, name string) *section {
	for i := range secs {
		if secs[i].name == name {
			return &secs[i]
		}
	}
	return nil
}

func loadDynsym(f *os.File, secs []section) ([]dynsym, []byte, *section, *section, error) {
	dyn := findSection(secs, ".dynsym")
	if dyn == nil {
		return nil, nil, nil, nil, errors.New("missing .dynsym")
	}
	if dyn.hdr.Type != SHT_DYNSYM {
		return nil, nil, nil, nil, fmt.Errorf(".dynsym wrong type: %d", dyn.hdr.Type)
	}
	if dyn.hdr.Entsize == 0 {
		return nil, nil, nil, nil, errors.New(".dynsym entsize is 0")
	}
	if dyn.hdr.Entsize != uint64(binary.Size(elf64Sym{})) {
		return nil, nil, nil, nil, fmt.Errorf("unexpected .dynsym entsize: %d", dyn.hdr.Entsize)
	}
	// Link points to the associated string table (.dynstr)
	if int(dyn.hdr.Link) >= len(secs) {
		return nil, nil, nil, nil, fmt.Errorf(".dynsym sh_link out of range: %d", dyn.hdr.Link)
	}
	dynstrSec := &secs[dyn.hdr.Link]
	if dynstrSec.hdr.Type != SHT_STRTAB {
		return nil, nil, nil, nil, fmt.Errorf(".dynsym link section is not STRTAB (type=%d)", dynstrSec.hdr.Type)
	}
	dynstr, err := readAtFull(f, int64(dynstrSec.hdr.Off), int(dynstrSec.hdr.Size))
	if err != nil {
		return nil, nil, nil, nil, fmt.Errorf("read .dynstr: %w", err)
	}
	count := int(dyn.hdr.Size / dyn.hdr.Entsize)
	syms := make([]dynsym, 0, count)
	for i := 0; i < count; i++ {
		var s elf64Sym
		off := int64(dyn.hdr.Off) + int64(i)*int64(dyn.hdr.Entsize)
		if err := readStructAt(f, off, &s); err != nil {
			return nil, nil, nil, nil, fmt.Errorf("read dynsym[%d]: %w", i, err)
		}
		name := readCString(dynstr, s.Name)
		syms = append(syms, dynsym{idx: i, sym: s, name: name})
	}
	return syms, dynstr, dyn, dynstrSec, nil
}

func patchRelocations(inPath, outPath, wrapper string) error {
	inF, err := os.Open(inPath)
	if err != nil {
		return err
	}
	defer inF.Close()

	st, err := inF.Stat()
	if err != nil {
		return err
	}
	size := st.Size()
	if size < 64 {
		return fmt.Errorf("file too small to be ELF64: %d bytes", size)
	}

	// Read ELF header but do not modify first 64 bytes.
	var eh elf64Ehdr
	if err := readStructAt(inF, 0, &eh); err != nil {
		return fmt.Errorf("read ELF header: %w", err)
	}
	if eh.Ident[0] != 0x7f || eh.Ident[1] != 'E' || eh.Ident[2] != 'L' || eh.Ident[3] != 'F' {
		return errors.New("not an ELF file")
	}
	if eh.Ident[4] != ELFCLASS64 {
		return fmt.Errorf("unsupported ELF class: %d", eh.Ident[4])
	}
	if eh.Ident[5] != ELFDATA2LSB {
		return fmt.Errorf("unsupported ELF data encoding: %d", eh.Ident[5])
	}
	if eh.Shoff == 0 {
		return errors.New("missing section header table")
	}

	secs, _, err := loadSections(inF, eh)
	if err != nil {
		return err
	}

	dynsyms, _, _, _, err := loadDynsym(inF, secs)
	if err != nil {
		return err
	}

	mallocIdx := -1
	wrapperIdx := -1
	for _, s := range dynsyms {
		if s.name == "malloc" {
			mallocIdx = s.idx
		}
		if s.name == wrapper {
			wrapperIdx = s.idx
		}
	}
	if wrapperIdx < 0 {
		return fmt.Errorf("wrapper symbol not found in .dynsym: %s", wrapper)
	}
	if mallocIdx < 0 {
		return fmt.Errorf("target symbol not found in .dynsym: malloc")
	}

	fmt.Fprintf(os.Stderr, "dynsym: malloc idx=%d, %s idx=%d\n", mallocIdx, wrapper, wrapperIdx)

	// Copy input to output first (preserve all bytes), then patch in-place.
	if err := os.MkdirAll(filepath.Dir(outPath), 0755); err != nil {
		return err
	}
	outF, err := os.OpenFile(outPath, os.O_CREATE|os.O_TRUNC|os.O_RDWR, 0755)
	if err != nil {
		return err
	}
	defer outF.Close()
	if _, err := inF.Seek(0, io.SeekStart); err != nil {
		return err
	}
	if _, err := io.Copy(outF, inF); err != nil {
		return err
	}
	if err := outF.Chmod(0755); err != nil {
		return err
	}

	patched := 0
	for _, sec := range secs {
		if sec.hdr.Type != SHT_RELA {
			continue
		}
		if sec.hdr.Entsize == 0 {
			continue
		}
		if sec.hdr.Entsize != uint64(binary.Size(elf64Rela{})) {
			continue
		}
		count := int(sec.hdr.Size / sec.hdr.Entsize)
		if count == 0 {
			continue
		}

		// Many relocation sections that refer to dynsym will have sh_link == dynsym index.
		if int(sec.hdr.Link) >= len(secs) {
			continue
		}
		if secs[sec.hdr.Link].name != ".dynsym" {
			continue
		}

		for i := 0; i < count; i++ {
			var r elf64Rela
			off := int64(sec.hdr.Off) + int64(i)*int64(sec.hdr.Entsize)
			if err := readStructAt(outF, off, &r); err != nil {
				return fmt.Errorf("read rela %s[%d]: %w", sec.name, i, err)
			}
			sym := relaSym(r.Info)
			typ := relaType(r.Info)
			if int(sym) == mallocIdx {
				newInfo := makeRelaInfo(uint32(wrapperIdx), typ)
				fmt.Fprintf(os.Stderr, "patch relocation: section=%s index=%d r_offset=0x%x type=%d sym=%d(malloc)->%d(%s)\n",
					sec.name, i, r.Off, typ, mallocIdx, wrapperIdx, wrapper)
				r.Info = newInfo
				var buf bytes.Buffer
				if err := binary.Write(&buf, binary.LittleEndian, &r); err != nil {
					return err
				}
				if _, err := outF.WriteAt(buf.Bytes(), off); err != nil {
					return fmt.Errorf("write rela %s[%d]: %w", sec.name, i, err)
				}
				patched++
			}
		}
	}

	if patched == 0 {
		return fmt.Errorf("no applicable RELA relocations referenced symbol malloc (idx=%d); nothing patched", mallocIdx)
	}
	fmt.Fprintf(os.Stderr, "patched %d relocation(s) targeting malloc -> %s\n", patched, wrapper)
	return nil
}

func usage() {
	fmt.Fprintf(os.Stderr, "usage: got-patch <input_elf> <output_elf> [wrapper_symbol]\n")
}

func main() {
	if len(os.Args) != 3 && len(os.Args) != 4 {
		usage()
		os.Exit(2)
	}
	inPath := os.Args[1]
	outPath := os.Args[2]
	wrapper := "logged_malloc"
	if len(os.Args) == 4 {
		wrapper = os.Args[3]
	}
	if err := patchRelocations(inPath, outPath, wrapper); err != nil {
		fmt.Fprintf(os.Stderr, "error: %v\n", err)
		os.Exit(1)
	}
}
EOF
